5	/**
6	 * Diameter of a Binary Tree.
7	 *
8	 * The diameter is the number of EDGES on the longest path between any two nodes
9	 * in the tree. That path may or may not pass through the root.
10	 *
11	 * Key insight: for any node, the longest path that BENDS at that node has length
12	 *   height(left) + height(right)   (in edges),
13	 * where height(x) = number of edges on the longest downward path from x to a leaf
14	 * (height of a null child = -1 in edge terms, height of a single node = 0).
15	 * The answer is the maximum such "bent" length over all nodes, computed in a
16	 * single post-order traversal.
17	 */
18	public class Solution {
19	
20	    /** Standard binary-tree node. */
21	    static class TreeNode {
22	        int val;
23	        TreeNode left, right;
24	        TreeNode(int val) { this.val = val; }
25	    }
26	
27	    /** Tracks the best diameter found so far across the recursion. */
28	    private int best;
29	
30	    /**
31	     * Returns the diameter (longest path length in edges) of the tree.
32	     * Empty tree (root == null) has diameter 0.
33	     */
34	    public int diameterOfBinaryTree(TreeNode root) {
35	        best = 0;
36	        height(root);
37	        return best;
38	    }
39	
40	    /**
41	     * Post-order height in EDGES. Height of null is -1 so that a leaf
42	     * (null+null children) reports height 0, and a node's height is
43	     * 1 + max(childHeights). While here, update `best` with the path that
44	     * bends at this node: (heightLeft + 1) + (heightRight + 1) edges, i.e.
45	     * leftEdges + rightEdges where leftEdges = heightLeft + 1.
46	     */
47	    private int height(TreeNode node) {
48	        if (node == null) return -1;
49	        int hl = height(node.left);
50	        int hr = height(node.right);
51	        // Edges going down through left subtree + edges through right subtree.
52	        int through = (hl + 1) + (hr + 1);
53	        if (through > best) best = through;
54	        return Math.max(hl, hr) + 1;
55	    }
56	
57	    // ------------------------------------------------------------------
58	    // I/O harness: builds a tree from a level-order line of tokens where
59	    // "null" marks an absent child (LeetCode-style), then prints the diameter.
60	    // Example input line:  1 2 3 null 4 5
61	    // ------------------------------------------------------------------
62	    public static void main(String[] args) {
63	        Scanner sc = new Scanner(System.in);
64	        if (!sc.hasNextLine()) {
65	            System.out.println(new Solution().diameterOfBinaryTree(null));
66	            return;
67	        }
68	        String line = sc.nextLine().trim();
69	        TreeNode root = build(line);
70	        System.out.println(new Solution().diameterOfBinaryTree(root));
71	    }
72	
73	    /** Build a tree from a space-separated level-order list ("null" = absent). */
74	    static TreeNode build(String line) {
75	        if (line.isEmpty()) return null;
76	        String[] tok = line.split("\\s+");
77	        if (tok.length == 0 || tok[0].equalsIgnoreCase("null")) return null;
78	        TreeNode root = new TreeNode(Integer.parseInt(tok[0]));
79	        Deque<TreeNode> q = new ArrayDeque<>();
80	        q.add(root);
81	        int i = 1;
82	        while (!q.isEmpty() && i < tok.length) {
83	            TreeNode cur = q.poll();
84	            if (i < tok.length && !tok[i].equalsIgnoreCase("null")) {
85	                cur.left = new TreeNode(Integer.parseInt(tok[i]));
86	                q.add(cur.left);
87	            }
88	            i++;
89	            if (i < tok.length && !tok[i].equalsIgnoreCase("null")) {
90	                cur.right = new TreeNode(Integer.parseInt(tok[i]));
91	                q.add(cur.right);
92	            }
93	            i++;
94	        }
95	        return root;
96	    }
97	}
