import java.util.*;
public class Verify {
    static class Node { int v; Node l, r; Node(int v){this.v=v;} }
    // Independent brute force: diameter = max over nodes of (heightNodes(left)+heightNodes(right)) in edges
    static int heightNodes(Node n){ if(n==null) return 0; return 1+Math.max(heightNodes(n.l), heightNodes(n.r)); }
    static int bruteBest;
    static void brute(Node n){ if(n==null) return; int d = heightNodes(n.l)+heightNodes(n.r); if(d>bruteBest) bruteBest=d; brute(n.l); brute(n.r); }
    static int bruteDiameter(Node n){ bruteBest=0; brute(n); return bruteBest; }

    // The solution's algorithm reimplemented
    static int best;
    static int height(Node n){ if(n==null) return -1; int hl=height(n.l), hr=height(n.r); int through=(hl+1)+(hr+1); if(through>best) best=through; return Math.max(hl,hr)+1; }
    static int solDiameter(Node n){ best=0; height(n); return best; }

    static Node randTree(Random rnd, int depth){
        if(depth<=0 || rnd.nextDouble()<0.3) return null;
        Node n = new Node(rnd.nextInt(100));
        n.l = randTree(rnd, depth-1);
        n.r = randTree(rnd, depth-1);
        return n;
    }
    public static void main(String[] a){
        Random rnd = new Random(42);
        int mism=0;
        for(int t=0;t<200000;t++){
            Node root = randTree(rnd, 7);
            if(root==null){ // empty tree both 0
                if(solDiameter(null)!=0) mism++;
                continue;
            }
            int s=solDiameter(root), b=bruteDiameter(root);
            if(s!=b){ mism++; if(mism<5) System.out.println("MISMATCH sol="+s+" brute="+b); }
        }
        System.out.println(mism==0? "ALL MATCH over 200000 random trees" : (mism+" mismatches"));
    }
}
